    TestObserver target(targetName);

    // 2. Get the observer graph instance using ObserverGraph::getInstance()
    reaction::ObserverGraph& graph = reaction::ObserverGraph::getInstance();

    // 3. Add the observer relationship using addObserver() method
    graph.addObserver(target.shared_from_this(), observer.shared_from_this());

