Based on the reference materials and detailed specifications, here's the complete implementation of the `test_field_binding` function:

```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// Helper types
// ============================================

class FieldOwnerNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        m_notificationCount++;
    }

    int getNotificationCount() const {
        return m_notificationCount;
    }

private:
    int m_notificationCount = 0;
};

class ProfileFields : public reaction::FieldBase {
public:
    ProfileFields(int initialScore, bool initialStatus)
        : m_score(initialScore), m_active(initialStatus) {}

    reaction::Var<int>& score() {
        return m_score;
    }

    reaction::Var<bool>& active() {
        return m_active;
    }

private:
    reaction::Var<int> m_score;
    reaction::Var<bool> m_active;
};

struct FieldBindingResult {
    int notificationsAfterScoreUpdate;
    int notificationsAfterStatusUpdate;
};

// ============================================
// Function implementation
// ============================================

FieldBindingResult test_field_binding(int initialScore, int scoreDelta) {
    // 1. Create ProfileFields object with initialScore and scoreDelta
    ProfileFields fields(initialScore, scoreDelta != 0);

    // 2. Create FieldOwnerNode
    FieldOwnerNode owner;

    // 3. Get observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 4. Register owner node
    observerGraph.addNode(&owner);

    // 5. Get field graph instance
    auto& fieldGraph = reaction::FieldGraph::getInstance();

    // 6. Bind fields to owner node
    fieldGraph.bindField(owner.getId(), fields.getId());

    // 7. Update score field
    fields.score().value(fields.score().get() + scoreDelta);

    // 8. Record notification count after score update
    int notificationsAfterScore = owner.getNotificationCount();

    // 9. Update active field
    fields.active().value(!fields.active().get());

    // 10. Record notification count after status update
    int notificationsAfterStatus = owner.getNotificationCount();

    // 11. Return notification counts
    return {notificationsAfterScore, notificationsAfterStatus};
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **ProfileFields Construction**: The object is created with `initialScore` and a boolean derived from `scoreDelta` (non-zero delta implies active status)

2. **FieldOwnerNode**: Inherits from `reaction::ObserverNode` and overrides `valueChanged()` to increment a notification counter

3. **Observer Graph Registration**: Uses `ObserverGraph::getInstance().addNode()` to register the owner node

4. **Field Binding**: Calls `FieldGraph::getInstance().bindField()` with the owner's ID and field's ID to establish the binding relationship

5. **Value Updates**: Uses the `value()` method on the reactive variables (`score()` and `active()`) to trigger notifications

6. **Notification Tracking**: The `getNotificationCount()` method returns the number of times `valueChanged()` was called

This implementation demonstrates proper usage of the reaction library's reactive programming patterns, including field binding, value updates, and notification handling.

