    // 1. Create RecordingNode instances
    RecordingNode sensor1;
    RecordingNode sensor2;

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    graph.addNode(sensor1);
    graph.addNode(sensor2);

    // 4. Set up initial dependency: sensor1 observes sensor2
    sensor1.addOneObserver(sensor2);

    // 5. Save node state for rollback
    auto rollbackFunc = graph.saveNodeStateForRollback(sensor1);

    // 6. Replace dependencies transactionally
    // Create a new set of dependencies (empty in this case)
    std::vector<reaction::ObserverNode*> newDependencies;
    graph.updateObserversTransactional(sensor1, newDependencies);

    // 7. Trigger notification on second sensor
